# Find the top k best selling food for each restaurant using HashMaps and priority queues
# Based on [#642](https://leetcode.com/problems/design-search-autocomplete-system) Design Autocomplete LC
```cpp
class Restaurants {
	//maps restaurant to food frequency
	map<string,map<string,int>> restaurantFoodMap;

	//restaraunt_name, food_name pairs
	Restaurants(vector<pair<string,string>> &restFoodPairs) {
		for(auto &restFoodPair:restFoodPairs) {
			restaurantFoodMap[restFoodPairs.first][restFoodPairs.second]++;
		}
	}

	vector<vector<string>> topKFood(int k) {
		vector<vector<string>> res;

		for(auto &restFoodFreqPair:restaurantFoodMap) {
			auto cmp = [&](pair<string,int> a,pair<string,int> b) {
				return (a.second>b.second || (a.second==b.second && a.first<b.first);
			}
			priority_queue<pair<string,int>,vector<pair<string,int>,decltype(cmp)> pq(cmp);

			for(auto kv:restFoodFreqPair) {
				pq.push(kv);
				if(pq.size()>k) {
					pq.pop();
				}
			}

			int size = pq.size();
			vector<string> ans(size,"");
			while(size--) {
				ans[size] = pq.top();
				pq.pop();
			}
			if(ans.size()) {
				res.push_back(ans);
			}			
		}

		return ans;
	}

};

import java.util.*;

public class ScratchPad {

    private Map<String, Map<String, Integer>> restaurantFoodMap;

    public ScratchPad(List<String[]> restFoodPairs) {
        restaurantFoodMap = new HashMap<String, Map<String, Integer>>();
        for (String[] restFoodPair : restFoodPairs) {
            if (!restaurantFoodMap.containsKey(restFoodPair[0])) {
                restaurantFoodMap.put(restFoodPair[0], new HashMap<String, Integer>());
            }
            Map<String, Integer> foodMap = restaurantFoodMap.get(restFoodPair[0]);
            Integer count = foodMap.containsKey(restFoodPair[1]) ? foodMap.get(restFoodPair[1]) : 0;
            foodMap.put(restFoodPair[1], count + 1);
        }
    }

    public List<List<String>> topKFood(int k) {
        List<List<String>> result = new ArrayList<List<String>>();
        for (Map.Entry<String, Map<String, Integer>> entry : restaurantFoodMap.entrySet()) {
            PriorityQueue<Map.Entry<String, Integer>> pq = new PriorityQueue<>(
                    new Comparator<Map.Entry<String, Integer>>() {
                        public int compare(Map.Entry<String, Integer> a, Map.Entry<String, Integer> b) {
                            int freqComp = b.getValue().compareTo(a.getValue());
                            if (freqComp != 0) return freqComp;
                            return a.getKey().compareTo(b.getKey());
                        }
                    }
            );

            pq.addAll(entry.getValue().entrySet());

            List<String> topFoods = new ArrayList<String>();
            int count = k;
            while (!pq.isEmpty() && count > 0) {
                topFoods.add(pq.poll().getKey());
                count--;
            }

            result.add(topFoods);
        }

        return result;
    }

    public static void main(String[] args) {
        List<String[]> menu = new ArrayList<String[]>();
        menu.add(new String[]{"RestaurantA", "apple"});
        menu.add(new String[]{"RestaurantA", "banana"});
        menu.add(new String[]{"RestaurantA", "apple"});
        menu.add(new String[]{"RestaurantB", "coke"});
        menu.add(new String[]{"RestaurantB", "coffee"});
        menu.add(new String[]{"RestaurantB", "coffee"});
        menu.add(new String[]{"RestaurantA", "banana"});
        menu.add(new String[]{"RestaurantA", "orange"});

        ScratchPad restaurants = new ScratchPad(menu);

        System.out.println("k = 2");
        System.out.println(restaurants.topKFood(2));

        System.out.println("\nk = 3");
        System.out.println(restaurants.topKFood(3));
    }
}


