import java.util.*;

public class ScratchPad {

    static class Food {
        String foodName;
        int freq;

        Food(String foodName, int freq) {
            this.foodName = foodName;
            this.freq = freq;
        }
    }

    public static void bestKSellingFood(List<String[]> menu, int k) {
        Map<String, Map<String, Integer>> map = new HashMap<String, Map<String, Integer>>();

        // Processing the input
        for (String[] m : menu) {
            if (!map.containsKey(m[0])) {
                Map<String, Integer> internalMap = new HashMap<String, Integer>();
                internalMap.put(m[1], 1);
                map.put(m[0], internalMap);
            } else {
                Map<String, Integer> internalMap = map.get(m[0]);
                if (!internalMap.containsKey(m[1])) {
                    internalMap.put(m[1], 1);
                } else {
                    internalMap.put(m[1], internalMap.get(m[1]) + 1);
                }
            }
        }

        // Generating the output
        for (Map.Entry<String, Map<String, Integer>> entry : map.entrySet()) {
            Map<String, Integer> internalMap = entry.getValue();
            PriorityQueue<Food> pq = new PriorityQueue<Food>(new Comparator<Food>() {
                public int compare(Food food1, Food food2) {
                    return food2.freq - food1.freq;
                }
            });

            for (Map.Entry<String, Integer> internalEntry : internalMap.entrySet()) {
                pq.add(new Food(internalEntry.getKey(), internalEntry.getValue()));
            }

            System.out.print(entry.getKey() + " => [");
            int bestK = k;
            while (!pq.isEmpty() && bestK > 0) {
                Food f = pq.poll();
                System.out.print(f.foodName + (bestK > 1 ? ", " : ""));
                bestK--;
            }
            System.out.println("]");
        }
    }

    public static void main(String[] args) {
        List<String[]> menu = new ArrayList<String[]>();
        menu.add(new String[]{"RestaurantA", "apple"});
        menu.add(new String[]{"RestaurantA", "banana"});
        menu.add(new String[]{"RestaurantA", "apple"});
        menu.add(new String[]{"RestaurantB", "coke"});
        menu.add(new String[]{"RestaurantB", "coffee"});
        menu.add(new String[]{"RestaurantB", "coffee"});
        menu.add(new String[]{"RestaurantA", "banana"});
        menu.add(new String[]{"RestaurantA", "orange"});

        System.out.println("k = 2");
        bestKSellingFood(menu, 2);

        System.out.println("\nk = 3");
        bestKSellingFood(menu, 3);
    }
}


